class ParseError(Exception):
    pass

class Parser:
    def __init__(self, text):
        self.text = text
        self.pos = 0
        self.len = len(text)

    def peek(self):
        if self.pos < self.len:
            return self.text[self.pos]
        return None

    def consume(self):
        self.pos += 1

    def skip_whitespace(self):
        while True:
            ch = self.peek()
            if ch in ' \t\n\r':
                self.consume()
            else:
                break

    def parse(self):
        self.skip_whitespace()
        value = self.parse_value()
        self.skip_whitespace()
        if self.pos != self.len:
            raise ParseError("Trailing garbage")
        return value

    def parse_value(self):
        self.skip_whitespace()
        ch = self.peek()
        if ch == '{':
            return self.parse_object()
        elif ch == '[':
            return self.parse_array()
        elif ch == '"':
            return self.parse_string()
        elif ch == 't':
            return self.parse_true()
        elif ch == 'f':
            return self.parse_false()
        elif ch == 'n':
            return self.parse_null()
        elif ch == '-' or (ch and ch.isdigit()):
            return self.parse_number()
        else:
            raise ParseError(f"Unexpected character: {ch}")

    def parse_object(self):
        self.consume()  # '{'
        self.skip_whitespace()
        if self.peek() == '}':
            self.consume()
            return {}
        result = {}
        while True:
            self.skip_whitespace()
            key = self.parse_string()
            if key is None:
                raise ParseError("Expected string key")
            self.skip_whitespace()
            if self.peek() != ':':
                raise ParseError("Expected ':' after key")
            self.consume()  # ':'
            self.skip_whitespace()
            value = self.parse_value()
            result[key] = value
            self.skip_whitespace()
            ch = self.peek()
            if ch == '}':
                self.consume()
                break
            elif ch == ',':
                self.consume()
                continue
            else:
                raise ParseError("Expected ',' or '}'")
        return result

    def parse_array(self):
        self.consume()  # '['
        self.skip_whitespace()
        if self.peek() == ']':
            self.consume()
            return []
        result = []
        while True:
            self.skip_whitespace()
            value = self.parse_value()
            result.append(value)
            self.skip_whitespace()
            ch = self.peek()
            if ch == ']':
                self.consume()
                break
            elif ch == ',':
                self.consume()
                continue
            else:
                raise ParseError("Expected ',' or ']'")
        return result

    def parse_string(self):
        if self.peek() != '"':
            raise ParseError("Expected '\"'")
        self.consume()  # opening quote
        chars = []
        while True:
            ch = self.peek()
            if ch is None:
                raise ParseError("Unterminated string")
            if ch == '"':
                self.consume()
                break
            elif ch == '\\':
                self.consume()
                esc = self.peek()
                if esc is None:
                    raise ParseError("Incomplete escape")
                if esc == '"':
                    chars.append('"')
                    self.consume()
                elif esc == '\\':
                    chars.append('\\')
                    self.consume()
                elif esc == '/':
                    chars.append('/')
                    self.consume()
                elif esc == 'b':
                    chars.append('\b')
                    self.consume()
                elif esc == 'f':
                    chars.append('\f')
                    self.consume()
                elif esc == 'n':
                    chars.append('\n')
                    self.consume()
                elif esc == 'r':
                    chars.append('\r')
                    self.consume()
                elif esc == 't':
                    chars.append('\t')
                    self.consume()
                elif esc == 'u':
                    self.consume()
                    hex_digits = ''
                    for _ in range(4):
                        h = self.peek()
                        if h is None or h not in '0123456789abcdefABCDEF':
                            raise ParseError("Invalid unicode escape")
                        hex_digits += h
                        self.consume()
                    code = int(hex_digits, 16)
                    chars.append(chr(code))
                else:
                    raise ParseError(f"Invalid escape: \\{esc}")
            else:
                # control character check
                if ord(ch) < 0x20:
                    raise ParseError("Control character in string")
                chars.append(ch)
                self.consume()
        return ''.join(chars)

    def parse_number(self):
        start = self.pos
        # optional minus
        if self.peek() == '-':
            self.consume()
        # integer part
        if self.peek() == '0':
            self.consume()
            # leading zero not allowed if followed by digit
            if self.peek() and self.peek().isdigit():
                raise ParseError("Leading zero")
        elif self.peek() and self.peek().isdigit():
            while self.peek() and self.peek().isdigit():
                self.consume()
        else:
            raise ParseError("Invalid number")
        is_float = False
        # fraction
        if self.peek() == '.':
            is_float = True
            self.consume()
            if not (self.peek() and self.peek().isdigit()):
                raise ParseError("Expected digit after '.'")
            while self.peek() and self.peek().isdigit():
                self.consume()
        # exponent
        if self.peek() in ('e', 'E'):
            is_float = True
            self.consume()
            if self.peek() in ('+', '-'):
                self.consume()
            if not (self.peek() and self.peek().isdigit()):
                raise ParseError("Expected digit in exponent")
            while self.peek() and self.peek().isdigit():
                self.consume()
        num_str = self.text[start:self.pos]
        try:
            if is_float:
                return float(num_str)
            else:
                return int(num_str)
        except ValueError:
            raise ParseError("Number conversion failed")

    def parse_true(self):
        if self.text.startswith('true', self.pos):
            self.pos += 4
            return True
        else:
            raise ParseError("Expected 'true'")

    def parse_false(self):
        if self.text.startswith('false', self.pos):
            self.pos += 5
            return False
        else:
            raise ParseError("Expected 'false'")

    def parse_null(self):
        if self.text.startswith('null', self.pos):
            self.pos += 4
            return None
        else:
            raise ParseError("Expected 'null'")

def parse(text: str):
    try:
        parser = Parser(text)
        return parser.parse()
    except ParseError:
        return None

